  import sailpoint.tools.Util;
  import sailpoint.object.Identity;

  ArrayList listLocations = new ArrayList();
  if (form.getField("dbFields") != null && form.getField("dbFields").getValue() != null && form.getField("healthministry") != null && form.getField("healthministry").getValue() != null) {

    List locationList = form.getField("dbFields").getValue().get("ps_ahhr_sailp_l_vw");
    if(!Util.isEmpty(locationList)){
      if(form.getField("contractorName")!=null @and form.getField("contractorName").getValue()!=null) {
          Identity identity = context.getObjectByName(Identity.class, form.getField("contractorName").getValue());
		  //Added the below lines by Rajesh to fix error on UI when submitting location data with -Offsite or -Remote locations.
          if (identity != null @and identity.getAttribute("location")!=null) {
          	listLocations.add(identity.getAttribute("location"));          
          }
      } 
      for (String eachLoc : locationList ) {
        if(eachLoc.startsWith(form.getField("healthministry").getValue())) {
          listLocations.add(eachLoc.split("\\|")[1]);
        }
      }
      Collections.sort(listLocations);
    }
  }
  
//log.error("listLocations*********"+listLocations.toString());
  return listLocations;
